import { Link, useNavigate } from 'react-router-dom';

import Button from '@mui/material/Button';
import FormHelperText from '@mui/material/FormHelperText';
import Grid from '@mui/material/Grid';
import InputLabel from '@mui/material/InputLabel';
import OutlinedInput from '@mui/material/OutlinedInput';
import Stack from '@mui/material/Stack';
import Typography from '@mui/material/Typography';

import { Formik } from 'formik';
import * as Yup from 'yup';

import useToast from 'app/providers/useToast';
import extractApiErrorMessage from 'utils/apiError';
import AuthWrapper from 'sections/auth/AuthWrapper';

import useAuth from '../useAuth';

export default function RegisterPage() {
  const navigate = useNavigate();
  const { showToast } = useToast();
  const { register } = useAuth();

  return (
    <AuthWrapper>
      <Grid container spacing={2}>
        <Grid size={12}>
          <Stack direction="row" sx={{ justifyContent: 'space-between', alignItems: 'baseline' }}>
            <Typography variant="h3">Registro</Typography>
            <Typography component={Link} to="/login" variant="body1" color="primary" sx={{ textDecoration: 'none' }}>
              Ya tengo cuenta
            </Typography>
          </Stack>
        </Grid>
        <Grid size={12}>
          <Formik
            initialValues={{
              email: '',
              first_name: '',
              last_name: '',
              phone: '',
              password: '',
              password_confirm: ''
            }}
            validationSchema={Yup.object({
              email: Yup.string().email('Correo inválido').required('Correo requerido'),
              first_name: Yup.string().required('Nombre requerido'),
              last_name: Yup.string().required('Apellido requerido'),
              password: Yup.string().min(8, 'Mínimo 8 caracteres').required('Contraseña requerida'),
              password_confirm: Yup.string()
                .required('Confirma la contraseña')
                .oneOf([Yup.ref('password')], 'Las contraseñas no coinciden')
            })}
            onSubmit={async (values, { setSubmitting }) => {
              try {
                const payload = {
                  email: values.email,
                  first_name: values.first_name,
                  last_name: values.last_name,
                  phone: values.phone,
                  password: values.password
                };
                await register(payload);
                showToast('Cuenta creada. Ahora inicia sesión.', 'success');
                navigate('/login');
              } catch (err) {
                const detail = extractApiErrorMessage(err, 'No fue posible registrar el usuario.');
                showToast(detail, 'error');
              } finally {
                setSubmitting(false);
              }
            }}
          >
            {({ values, errors, touched, handleBlur, handleChange, handleSubmit, isSubmitting }) => (
              <form onSubmit={handleSubmit}>
                <Grid container spacing={2}>
                  {[
                    { name: 'email', label: 'Email', type: 'email' },
                    { name: 'first_name', label: 'Nombre' },
                    { name: 'last_name', label: 'Apellido' },
                    { name: 'phone', label: 'Teléfono' },
                    { name: 'password', label: 'Contraseña', type: 'password' },
                    { name: 'password_confirm', label: 'Confirmar contraseña', type: 'password' }
                  ].map((field) => (
                    <Grid key={field.name} size={{ xs: 12, md: 6 }}>
                      <Stack sx={{ gap: 1 }}>
                        <InputLabel htmlFor={field.name}>{field.label}</InputLabel>
                        <OutlinedInput
                          id={field.name}
                          name={field.name}
                          type={field.type || 'text'}
                          value={values[field.name]}
                          onBlur={handleBlur}
                          onChange={handleChange}
                        />
                        {touched[field.name] && errors[field.name] ? <FormHelperText error>{errors[field.name]}</FormHelperText> : null}
                      </Stack>
                    </Grid>
                  ))}
                  <Grid size={12}>
                    <Button type="submit" variant="contained" fullWidth disabled={isSubmitting}>
                      Registrar
                    </Button>
                  </Grid>
                </Grid>
              </form>
            )}
          </Formik>
        </Grid>
      </Grid>
    </AuthWrapper>
  );
}
